    //  ###
    //  .#.
    const input: [number, number][] = [
      [1, 0],
      [0, 1], [1, 1], [2, 1],
      [1, 2],
    ];
    expect(toKeys(nextGeneration(input)).has("1,1")).toBe(false);
  });
